"""Object-storage abstraction.

The rest of the app depends on the `StorageBackend` interface, not on boto3
directly, so the storage provider can be swapped (e.g. to MinIO) without
touching business logic.
"""
from __future__ import annotations

from abc import ABC, abstractmethod

import boto3

from app.config import Settings, get_settings

# S3 presigned-POST policy condition name for enforcing an upload size range.
CONTENT_LENGTH_RANGE = "content-length-range"


class PresignedPost:
    def __init__(self, url: str, fields: dict[str, str]) -> None:
        self.url = url
        self.fields = fields


class StorageBackend(ABC):
    @abstractmethod
    def create_presigned_post(
        self, bucket: str, key: str, content_type: str, max_bytes: int, expiry_seconds: int
    ) -> PresignedPost: ...

    @abstractmethod
    def create_presigned_get(
        self, bucket: str, key: str, expiry_seconds: int, download_filename: str
    ) -> str: ...

    @abstractmethod
    def download_bytes(self, bucket: str, key: str) -> bytes: ...

    @abstractmethod
    def copy(self, src_bucket: str, src_key: str, dst_bucket: str, dst_key: str) -> None: ...

    @abstractmethod
    def delete(self, bucket: str, key: str) -> None: ...


class S3Storage(StorageBackend):
    def __init__(self, settings: Settings) -> None:
        self._client = boto3.client(
            "s3",
            region_name=settings.aws_region,
            aws_access_key_id=settings.aws_access_key_id or None,
            aws_secret_access_key=settings.aws_secret_access_key or None,
        )

    def create_presigned_post(
        self, bucket: str, key: str, content_type: str, max_bytes: int, expiry_seconds: int
    ) -> PresignedPost:
        # Conditions are enforced by S3 itself, so an oversized or wrong-type
        # upload is rejected at the edge before it ever reaches the worker.
        response = self._client.generate_presigned_post(
            Bucket=bucket,
            Key=key,
            Fields={"Content-Type": content_type},
            Conditions=[
                {"Content-Type": content_type},
                [CONTENT_LENGTH_RANGE, 1, max_bytes],
            ],
            ExpiresIn=expiry_seconds,
        )
        return PresignedPost(url=response["url"], fields=response["fields"])

    def create_presigned_get(
        self, bucket: str, key: str, expiry_seconds: int, download_filename: str
    ) -> str:
        return self._client.generate_presigned_url(
            "get_object",
            Params={
                "Bucket": bucket,
                "Key": key,
                "ResponseContentDisposition": f'attachment; filename="{download_filename}"',
            },
            ExpiresIn=expiry_seconds,
        )

    def download_bytes(self, bucket: str, key: str) -> bytes:
        response = self._client.get_object(Bucket=bucket, Key=key)
        return response["Body"].read()

    def copy(self, src_bucket: str, src_key: str, dst_bucket: str, dst_key: str) -> None:
        self._client.copy_object(
            Bucket=dst_bucket,
            Key=dst_key,
            CopySource={"Bucket": src_bucket, "Key": src_key},
        )

    def delete(self, bucket: str, key: str) -> None:
        self._client.delete_object(Bucket=bucket, Key=key)


def get_storage() -> StorageBackend:
    return S3Storage(get_settings())

"""Single source of truth for how S3 object keys are constructed.

Keys are namespaced by document id so the worker can recover the owning
`Document` from an S3 event, and so one upload can never overwrite another.
"""
import re
import uuid

_UNSAFE_CHARS = re.compile(r"[^A-Za-z0-9._-]+")


def sanitize_filename(filename: str) -> str:
    cleaned = _UNSAFE_CHARS.sub("_", filename.strip()) or "file"
    return cleaned[:200]


def build_object_key(document_id: uuid.UUID, filename: str) -> str:
    return f"{document_id}/{sanitize_filename(filename)}"


def document_id_from_key(key: str) -> uuid.UUID | None:
    prefix = key.split("/", 1)[0]
    try:
        return uuid.UUID(prefix)
    except ValueError:
        return None

"""Repository read API: list, detail, and presigned download."""
import uuid

from fastapi import APIRouter, Depends, HTTPException, Query, status
from sqlalchemy import func, or_, select
from sqlalchemy.orm import Session

from app.config import Settings, get_settings
from app.db import get_db
from app.enums import DocumentStatus, DocumentType
from app.models import Document
from app.schemas import DocumentListResponse, DocumentOut, DownloadResponse
from app.storage import StorageBackend, get_storage

router = APIRouter(prefix="/api/documents", tags=["documents"])

DEFAULT_PAGE_SIZE = 50
MAX_PAGE_SIZE = 200


@router.get("", response_model=DocumentListResponse)
def list_documents(
    db: Session = Depends(get_db),
    q: str | None = Query(default=None, description="Search filename or counterparty"),
    document_type: DocumentType | None = None,
    status_filter: DocumentStatus | None = Query(default=None, alias="status"),
    limit: int = Query(default=DEFAULT_PAGE_SIZE, ge=1, le=MAX_PAGE_SIZE),
    offset: int = Query(default=0, ge=0),
) -> DocumentListResponse:
    filters = []
    if q:
        pattern = f"%{q}%"
        filters.append(or_(Document.filename.ilike(pattern), Document.counterparty.ilike(pattern)))
    if document_type is not None:
        filters.append(Document.document_type == document_type)
    if status_filter is not None:
        filters.append(Document.status == status_filter)

    total = db.scalar(select(func.count()).select_from(Document).where(*filters)) or 0
    rows = db.scalars(
        select(Document)
        .where(*filters)
        .order_by(Document.created_at.desc())
        .limit(limit)
        .offset(offset)
    ).all()
    return DocumentListResponse(
        items=[DocumentOut.model_validate(row) for row in rows], total=total
    )


@router.get("/{document_id}", response_model=DocumentOut)
def get_document(document_id: uuid.UUID, db: Session = Depends(get_db)) -> DocumentOut:
    document = db.get(Document, document_id)
    if document is None:
        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Document not found")
    return DocumentOut.model_validate(document)


@router.get("/{document_id}/download", response_model=DownloadResponse)
def download_document(
    document_id: uuid.UUID,
    db: Session = Depends(get_db),
    storage: StorageBackend = Depends(get_storage),
    settings: Settings = Depends(get_settings),
) -> DownloadResponse:
    document = db.get(Document, document_id)
    if document is None:
        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Document not found")
    if document.status != DocumentStatus.READY or not document.s3_key or not document.s3_bucket:
        raise HTTPException(
            status_code=status.HTTP_409_CONFLICT,
            detail="Document is not available for download yet",
        )

    url = storage.create_presigned_get(
        bucket=document.s3_bucket,
        key=document.s3_key,
        expiry_seconds=settings.presign_expiry_seconds,
        download_filename=document.filename,
    )
    return DownloadResponse(url=url)

