"""Content type sniffing and text/metadata extraction.

This module is the only place that parses untrusted file bytes. It MUST run
inside the sandboxed worker (unprivileged, no outbound network, resource
limited) because a malformed file can target parser vulnerabilities, which a
malware signature scan does not cover.
"""
import io
from dataclasses import dataclass, field

from langdetect import LangDetectException, detect
from pypdf import PdfReader
from pypdf.errors import PdfReadError

CONTENT_TYPE_PDF = "application/pdf"
CONTENT_TYPE_DOCX = "application/vnd.openxmlformats-officedocument.wordprocessingml.document"
CONTENT_TYPE_DOC = "application/msword"

_PDF_SIGNATURE = b"%PDF-"
_ZIP_SIGNATURE = b"PK\x03\x04"  # DOCX is a zip container
_OLE_SIGNATURE = b"\xd0\xcf\x11\xe0"  # legacy .doc
_MIN_TEXT_FOR_LANGUAGE = 20


@dataclass
class ExtractionResult:
    detected_content_type: str | None = None
    is_encrypted: bool = False
    page_count: int | None = None
    language: str | None = None
    text: str | None = None
    extracted_fields: list[str] = field(default_factory=list)


def sniff_content_type(content: bytes) -> str | None:
    """Identify the true type from magic bytes, ignoring the declared type."""
    if content.startswith(_PDF_SIGNATURE):
        return CONTENT_TYPE_PDF
    if content.startswith(_ZIP_SIGNATURE):
        return CONTENT_TYPE_DOCX
    if content.startswith(_OLE_SIGNATURE):
        return CONTENT_TYPE_DOC
    return None


def extract(content: bytes, detected_content_type: str | None) -> ExtractionResult:
    result = ExtractionResult(detected_content_type=detected_content_type)
    if detected_content_type != CONTENT_TYPE_PDF:
        # Non-PDF text extraction (DOCX/OCR) is deferred; the file is still
        # stored and downloadable, just without extracted metadata for now.
        return result

    try:
        reader = PdfReader(io.BytesIO(content))
    except PdfReadError:
        return result

    if reader.is_encrypted:
        result.is_encrypted = True
        return result

    result.page_count = len(reader.pages)
    result.text = _extract_text(reader)
    result.language = _detect_language(result.text)

    if result.page_count is not None:
        result.extracted_fields.append("page_count")
    if result.language is not None:
        result.extracted_fields.append("language")
    return result


def _extract_text(reader: PdfReader) -> str:
    parts = [page.extract_text() or "" for page in reader.pages]
    return "\n".join(parts).strip()


def _detect_language(text: str) -> str | None:
    if len(text) < _MIN_TEXT_FOR_LANGUAGE:
        return None
    try:
        return detect(text)
    except LangDetectException:
        return None

