interface InitiateUploadArgs {
  file: File;
  metadata: DocumentMetadataInput;
}

async function initiateUpload({ file, metadata }: InitiateUploadArgs): Promise<UploadInitResponse> {
  const { data } = await apiClient.post<UploadInitResponse>("/api/uploads", {
    filename: file.name,
    content_type: file.type,
    size_bytes: file.size,
    metadata,
  });
  return data;
}

type ProgressHandler = (percent: number) => void;

/** Posts the file straight to S3 (quarantine) using the presigned policy. */
async function uploadToStorage(
  init: UploadInitResponse,
  file: File,
  onProgress?: ProgressHandler,
): Promise<void> {
  const form = new FormData();
  Object.entries(init.upload.fields).forEach(([key, value]) => form.append(key, value));
  form.append("file", file); // the file field must come last for S3

  // A bare axios call (no app auth headers) so we don't break the S3 signature.
  await axios.post(init.upload.url, form, {
    onUploadProgress: (event) => {
      if (onProgress && event.total) {
        onProgress(Math.round((event.loaded / event.total) * 100));
      }
    },
  });
}

export async function uploadDocument(
  args: InitiateUploadArgs,
  onProgress?: ProgressHandler,
): Promise<string> {
  const init = await initiateUpload(args);
  await uploadToStorage(init, args.file, onProgress);
  return init.document_id;
}

function cleanParams(params: ListParams): ListParams {
  return Object.fromEntries(
    Object.entries(params).filter(([, value]) => value !== undefined && value !== ""),
  );
}

