import { useId, useRef, useState } from "react";

import { ACCEPTED_MIME_TYPES, MAX_UPLOAD_BYTES } from "../lib/constants";

interface DropzoneProps {
  file: File | null;
  onFileSelected: (file: File) => void;
  disabled?: boolean;
}

function formatBytes(bytes: number): string {
  const mb = bytes / (1024 * 1024);
  return `${mb.toFixed(2)} MB`;
}

export function Dropzone({ file, onFileSelected, disabled = false }: DropzoneProps) {
  const inputRef = useRef<HTMLInputElement>(null);
  const inputId = useId();
  const [isDragging, setIsDragging] = useState(false);
  const [error, setError] = useState<string | null>(null);

  function validateAndSelect(candidate: File | undefined) {
    if (!candidate) return;
    if (!ACCEPTED_MIME_TYPES.includes(candidate.type)) {
      setError("Only PDF and Word documents are supported.");
      return;
    }
    if (candidate.size > MAX_UPLOAD_BYTES) {
      setError(`File exceeds the ${formatBytes(MAX_UPLOAD_BYTES)} limit.`);
      return;
    }
    setError(null);
    onFileSelected(candidate);
  }

  return (
    <div>
      <label htmlFor={inputId} className="mb-1.5 block text-sm font-medium text-slate-700">
        Document file
      </label>
      <div
        role="button"
        tabIndex={0}
        aria-disabled={disabled}
        onClick={() => !disabled && inputRef.current?.click()}
        onKeyDown={(event) => {
          if (!disabled && (event.key === "Enter" || event.key === " ")) {
            event.preventDefault();
            inputRef.current?.click();
          }
        }}
        onDragOver={(event) => {
          event.preventDefault();
          if (!disabled) setIsDragging(true);
        }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(event) => {
          event.preventDefault();
          setIsDragging(false);
          if (!disabled) validateAndSelect(event.dataTransfer.files[0]);
        }}
        className={`flex cursor-pointer flex-col items-center justify-center rounded-lg border-2 border-dashed px-6 py-10 text-center transition-colors ${
          isDragging ? "border-indigo-500 bg-indigo-50" : "border-slate-300 bg-slate-50"
        } ${disabled ? "cursor-not-allowed opacity-60" : "hover:border-indigo-400"}`}
      >
        <p className="text-sm text-slate-600">
          {file ? (
            <span className="font-medium text-slate-900">
              {file.name} <span className="text-slate-500">({formatBytes(file.size)})</span>
            </span>
          ) : (
            <>
              <span className="font-medium text-indigo-600">Click to browse</span> or drag a file
              here
            </>
          )}
        </p>
        <p className="mt-1 text-xs text-slate-400">PDF or Word, up to {formatBytes(MAX_UPLOAD_BYTES)}</p>
        <input
          ref={inputRef}
          id={inputId}
          type="file"
          accept={ACCEPTED_MIME_TYPES.join(",")}
          className="hidden"
          disabled={disabled}
          onChange={(event) => validateAndSelect(event.target.files?.[0])}
        />
      </div>
      {error && (
        <p role="alert" className="mt-1.5 text-sm text-red-600">
          {error}
        </p>
      )}
    </div>
  );
}

import { useState } from "react";
import { useMutation, useQuery } from "@tanstack/react-query";

import { Dropzone } from "../components/Dropzone";
import { StatusBadge } from "../components/StatusBadge";
import { getDocument, uploadDocument } from "../api/documents";
import { IN_PROGRESS_STATUSES, STATUS_POLL_INTERVAL_MS } from "../lib/constants";
import { SELECTABLE_DOCUMENT_TYPES, DOCUMENT_TYPE_LABELS } from "../lib/documentTypes";
import type { DocumentMetadataInput, DocumentType } from "../types";

const EMPTY_METADATA: DocumentMetadataInput = {};

export function UploadPage() {
  const [file, setFile] = useState<File | null>(null);
  const [metadata, setMetadata] = useState<DocumentMetadataInput>(EMPTY_METADATA);
  const [progress, setProgress] = useState(0);
  const [uploadedId, setUploadedId] = useState<string | null>(null);

  const uploadMutation = useMutation({
    mutationFn: () => {
      if (!file) throw new Error("No file selected");
      return uploadDocument({ file, metadata }, setProgress);
    },
    onSuccess: (documentId) => setUploadedId(documentId),
  });

  // After upload, poll the document until the pipeline reaches a terminal state.
  const statusQuery = useQuery({
    queryKey: ["document", uploadedId],
    queryFn: () => getDocument(uploadedId as string),
    enabled: uploadedId !== null,
    refetchInterval: (query) => {
      const status = query.state.data?.status;
      return status && IN_PROGRESS_STATUSES.includes(status) ? STATUS_POLL_INTERVAL_MS : false;
    },
  });

  function resetForm() {
    setFile(null);
    setMetadata(EMPTY_METADATA);
    setProgress(0);
    setUploadedId(null);
    uploadMutation.reset();
  }

  const isUploading = uploadMutation.isPending;

  return (
    <section className="mx-auto max-w-2xl">
      <h1 className="text-2xl font-semibold text-slate-900">Upload a document</h1>
      <p className="mt-1 text-sm text-slate-500">
        Files are scanned for malware and processed before they appear in the repository. Metadata
        is optional.
      </p>

      <form
        className="mt-6 space-y-5"
        onSubmit={(event) => {
          event.preventDefault();
          uploadMutation.mutate();
        }}
      >
        <Dropzone file={file} onFileSelected={setFile} disabled={isUploading || uploadedId !== null} />

        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
          <TextField
            label="Counterparty"
            value={metadata.counterparty ?? ""}
            onChange={(value) => setMetadata((m) => ({ ...m, counterparty: value }))}
          />
          <SelectField
            label="Document type"
            value={metadata.document_type ?? ""}
            onChange={(value) =>
              setMetadata((m) => ({ ...m, document_type: (value || undefined) as DocumentType }))
            }
          />
          <TextField
            label="Effective date"
            type="date"
            value={metadata.effective_date ?? ""}
            onChange={(value) => setMetadata((m) => ({ ...m, effective_date: value }))}
          />
          <TextField
            label="Legal entity"
            value={metadata.legal_entity ?? ""}
            onChange={(value) => setMetadata((m) => ({ ...m, legal_entity: value }))}
          />
          <TextField
            label="Jira case ID"
            value={metadata.jira_case_id ?? ""}
            onChange={(value) => setMetadata((m) => ({ ...m, jira_case_id: value }))}
          />
          <TextField
            label="Zammad ticket ID"
            value={metadata.zammad_ticket_id ?? ""}
            onChange={(value) => setMetadata((m) => ({ ...m, zammad_ticket_id: value }))}
          />
        </div>

        {isUploading && <ProgressBar percent={progress} />}

        {uploadMutation.isError && (
          <p role="alert" className="text-sm text-red-600">
            Upload failed. Please try again.
          </p>
        )}

        <div className="flex gap-3">
          <button
            type="submit"
            disabled={!file || isUploading || uploadedId !== null}
            className="rounded-md bg-indigo-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-indigo-700 focus:outline-none focus-visible:ring-2 focus-visible:ring-indigo-500 disabled:cursor-not-allowed disabled:opacity-50"
          >
            {isUploading ? "Uploading…" : "Upload document"}
          </button>
          {uploadedId && (
            <button
              type="button"
              onClick={resetForm}
              className="rounded-md border border-slate-300 px-4 py-2 text-sm font-medium text-slate-700 hover:bg-slate-50"
            >
              Upload another
            </button>
          )}
        </div>
      </form>

      {uploadedId && statusQuery.data && (
        <div className="mt-6 rounded-lg border border-slate-200 bg-white p-4">
          <div className="flex items-center justify-between">
            <span className="text-sm font-medium text-slate-700">Processing status</span>
            <StatusBadge status={statusQuery.data.status} />
          </div>
          {statusQuery.data.status_detail && (
            <p className="mt-2 text-sm text-slate-500">{statusQuery.data.status_detail}</p>
          )}
        </div>
      )}
    </section>
  );
}

interface FieldProps {
  label: string;
  value: string;
  onChange: (value: string) => void;
  type?: string;
}

function TextField({ label, value, onChange, type = "text" }: FieldProps) {
  return (
    <label className="block text-sm">
      <span className="mb-1.5 block font-medium text-slate-700">{label}</span>
      <input
        type={type}
        value={value}
        onChange={(event) => onChange(event.target.value)}
        className="w-full rounded-md border border-slate-300 px-3 py-2 text-sm shadow-sm focus:border-indigo-500 focus:outline-none focus:ring-1 focus:ring-indigo-500"
      />
    </label>
  );
}

function SelectField({ label, value, onChange }: Omit<FieldProps, "type">) {
  return (
    <label className="block text-sm">
      <span className="mb-1.5 block font-medium text-slate-700">{label}</span>
      <select
        value={value}
        onChange={(event) => onChange(event.target.value)}
        className="w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm shadow-sm focus:border-indigo-500 focus:outline-none focus:ring-1 focus:ring-indigo-500"
      >
        <option value="">Auto / unclassified</option>
        {SELECTABLE_DOCUMENT_TYPES.map((type) => (
          <option key={type} value={type}>
            {DOCUMENT_TYPE_LABELS[type]}
          </option>
        ))}
      </select>
    </label>
  );
}

function ProgressBar({ percent }: { percent: number }) {
  return (
    <div
      className="h-2 w-full overflow-hidden rounded-full bg-slate-200"
      role="progressbar"
      aria-valuenow={percent}
      aria-valuemin={0}
      aria-valuemax={100}
    >
      <div
        className="h-full bg-indigo-600 transition-all"
        style={{ width: `${percent}%` }}
      />
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";

import { StatusBadge } from "../components/StatusBadge";
import { getDownloadUrl, listDocuments } from "../api/documents";
import { DOCUMENT_TYPE_LABELS, SELECTABLE_DOCUMENT_TYPES } from "../lib/documentTypes";
import type { DocumentOut } from "../types";

export function RepositoryPage() {
  const [search, setSearch] = useState("");
  const [typeFilter, setTypeFilter] = useState("");

  const documentsQuery = useQuery({
    queryKey: ["documents", search, typeFilter],
    queryFn: () => listDocuments({ q: search, document_type: typeFilter }),
  });

  return (
    <section className="mx-auto max-w-6xl">
      <h1 className="text-2xl font-semibold text-slate-900">Repository</h1>
      <p className="mt-1 text-sm text-slate-500">
        Browse uploaded contracts and supporting documents.
      </p>

      <div className="mt-6 flex flex-col gap-3 sm:flex-row">
        <input
          type="search"
          value={search}
          onChange={(event) => setSearch(event.target.value)}
          placeholder="Search filename or counterparty…"
          aria-label="Search documents"
          className="flex-1 rounded-md border border-slate-300 px-3 py-2 text-sm shadow-sm focus:border-indigo-500 focus:outline-none focus:ring-1 focus:ring-indigo-500"
        />
        <select
          value={typeFilter}
          onChange={(event) => setTypeFilter(event.target.value)}
          aria-label="Filter by document type"
          className="rounded-md border border-slate-300 bg-white px-3 py-2 text-sm shadow-sm focus:border-indigo-500 focus:outline-none focus:ring-1 focus:ring-indigo-500"
        >
          <option value="">All types</option>
          {SELECTABLE_DOCUMENT_TYPES.map((type) => (
            <option key={type} value={type}>
              {DOCUMENT_TYPE_LABELS[type]}
            </option>
          ))}
        </select>
      </div>

      <div className="mt-4 overflow-hidden rounded-lg border border-slate-200 bg-white">
        {documentsQuery.isLoading ? (
          <Message text="Loading documents…" />
        ) : documentsQuery.isError ? (
          <Message text="Could not load documents. Is the backend running?" tone="error" />
        ) : documentsQuery.data && documentsQuery.data.items.length > 0 ? (
          <DocumentsTable items={documentsQuery.data.items} />
        ) : (
          <Message text="No documents yet. Upload one to get started." />
        )}
      </div>
    </section>
  );
}

function DocumentsTable({ items }: { items: DocumentOut[] }) {
  return (
    <table className="min-w-full divide-y divide-slate-200 text-sm">
      <thead className="bg-slate-50 text-left text-xs font-medium uppercase tracking-wide text-slate-500">
        <tr>
          <th className="px-4 py-3">Document</th>
          <th className="px-4 py-3">Type</th>
          <th className="px-4 py-3">Counterparty</th>
          <th className="px-4 py-3">Status</th>
          <th className="px-4 py-3">Uploaded</th>
          <th className="px-4 py-3 text-right">Actions</th>
        </tr>
      </thead>
      <tbody className="divide-y divide-slate-100">
        {items.map((doc) => (
          <tr key={doc.id} className="hover:bg-slate-50">
            <td className="px-4 py-3 font-medium text-slate-900">{doc.filename}</td>
            <td className="px-4 py-3 text-slate-600">{DOCUMENT_TYPE_LABELS[doc.document_type]}</td>
            <td className="px-4 py-3 text-slate-600">{doc.counterparty ?? "—"}</td>
            <td className="px-4 py-3">
              <StatusBadge status={doc.status} />
            </td>
            <td className="px-4 py-3 text-slate-500">
              {new Date(doc.created_at).toLocaleDateString()}
            </td>
            <td className="px-4 py-3 text-right">
              <DownloadButton document={doc} />
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

function DownloadButton({ document }: { document: DocumentOut }) {
  const [isLoading, setIsLoading] = useState(false);

  async function handleDownload() {
    setIsLoading(true);
    try {
      const url = await getDownloadUrl(document.id);
      window.open(url, "_blank", "noopener,noreferrer");
    } finally {
      setIsLoading(false);
    }
  }

  if (document.status !== "ready") {
    return <span className="text-xs text-slate-400">Unavailable</span>;
  }

  return (
    <button
      type="button"
      onClick={handleDownload}
      disabled={isLoading}
      className="rounded-md border border-slate-300 px-3 py-1.5 text-xs font-medium text-slate-700 hover:bg-slate-100 disabled:opacity-50"
    >
      {isLoading ? "Preparing…" : "Download"}
    </button>
  );
}

function Message({ text, tone = "muted" }: { text: string; tone?: "muted" | "error" }) {
  const color = tone === "error" ? "text-red-600" : "text-slate-500";
  return <p className={`px-4 py-10 text-center text-sm ${color}`}>{text}</p>;
}

